protected void enableHeaderManage()
{
    next enableHeaderManage();

    page.actionPaneControlEnabled(formControlStr(PurchTable, ButtonInterCompanySalesTable), purchTableInteractionHelper.parmintercompanySalesTableEnabled());

    if(purchTable.ETG_IsThirdParty && purchTable.ETG_TPSalesId)
    {
        page.actionPaneControlEnabled(formControlStr(PurchTable, ButtonInterCompanySalesTableTP), true);
    }
    else
    {
        page.actionPaneControlEnabled(formControlStr(PurchTable, ButtonInterCompanySalesTableTP), false);
    }
}

/// <summary>
/// Disabling AddLines and AddProducts button  in case of Agreement exists for this order
/// </summary>
/// <param name="args"></param>
[PostHandlerFor(classStr(PurchTableInteraction), methodStr(PurchTableInteraction, purchLine_DS_selectionChanged))]
public static void PurchTableInteraction_Post_purchLine_DS_selectionChanged(XppPrePostArgs args)
{
    PurchTableInteraction   purchTableInteraction   = args.getThis();
    PurchTable              purchTable              = purchTableInteraction.page().activeRecord(identifierStr(PurchTable)) as PurchTable;
    ETG_Parameters          parameter               = ETG_Parameters::find();

    if(parameter.ETG_FrozenValidations == NoYes::Yes
        && parameter.ETG_FrozenValidationPurchaseOrder == NoYes::Yes)
    {
        purchTableInteraction.page().actionPaneControlEnabled(formControlStr(PurchTable, ButtonLineQuickQuote), purchTable.MatchingAgreement == 0);
        purchTableInteraction.page().actionPaneControlEnabled(formControlStr(PurchTable, RetailAddItemMenuItem), purchTable.MatchingAgreement == 0);
        purchTableInteraction.page().actionPaneControlEnabled(formControlStr(PurchTable, MarkupTrans_HeadingPurchTable), purchTable.MatchingAgreement == 0);
        purchTableInteraction.page().actionPaneControlEnabled(formControlStr(PurchTable, MarkupTrans_LinePurchTable), purchTable.MatchingAgreement == 0);
    }
}
